#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, B, C;
        scanf("%d %d", &X, &B);
        long long int people = 1;
        int xi[B], yi[B];
        for (int i = 0; i < B; i++) {
            scanf("%d %d", &xi[i], &yi[i]);
            people += yi[i];
        }
        scanf("%d", &C);
        int pi[C], qi[C], ri[C];
        for (int i = 0; i < C; i++) {
            scanf("%d %d %d", &pi[i], &qi[i], &ri[i]);
        }
        long long int minPeople = people;
        for (int i = 0; i < B; i++) {
            people -= yi[i];
            for (int j = 0; j < C; j++) {
                if (pi[j] >= xi[i] && people >= qi[j]) {
                    people += ri[j];
                }
            }
            if (people < minPeople) {
                minPeople = people;
            }
        }
        printf("%lld\n", minPeople);
    }
    return 0;
}

