import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt();
            int B = sc.nextInt();
            long people = 1;
            int[] xi = new int[B];
            int[] yi = new int[B];
            for (int i = 0; i < B; i++) {
                xi[i] = sc.nextInt();
                yi[i] = sc.nextInt();
                people += yi[i];
            }
            int C = sc.nextInt();
            int[] pi = new int[C];
            int[] qi = new int[C];
            int[] ri = new int[C];
            for (int i = 0; i < C; i++) {
                pi[i] = sc.nextInt();
                qi[i] = sc.nextInt();
                ri[i] = sc.nextInt();
            }
            long minPeople = people;
            for (int i = 0; i < B; i++) {
                people -= yi[i];
                for (int j = 0; j < C; j++) {
                    if (pi[j] >= xi[i] && people >= qi[j]) {
                        people += ri[j];
                    }
