const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [X, B] = readline().split(' ').map(Number);
    let people = 1;
    const xi = [];
    const yi = [];
    for (let j = 0; j < B; j++) {
        const [x, y] = readline().split(' ').map(Number);
        xi.push(x);
        yi.push(y);
        people += y;
    }
    const C = parseInt(readline());
    const pi = [];
    const qi = [];
    const ri = [];
    for (let j = 0; j < C; j++) {
        const [p, q, r] = readline().split(' ').map(Number);
        pi.push(p);
        qi.push(q);
        ri.push(r);
    }
    let minPeople = people;
    for (let j = 0; j < B; j++) {
        people -= yi[j];
        for (let k = 0; k < C; k++) {
            if (pi[k] >= xi[j] && people >= qi[k]) {
                people += ri[k];
            }
        }
        if (people < minPeople) {
            minPeople = people;
        }
    }
    console.log(minPeople);
}

